const express = require('express');
const cors = require('cors');
const mysql = require('mysql2');
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const helmet = require('helmet');
const morgan = require('morgan');
const rateLimit = require('express-rate-limit');
const multer = require('multer');
const path = require('path');
const http = require('http');
const { Server } = require('socket.io');

const app = express();
const server = http.createServer(app);
const io = new Server(server, { cors: { origin: "*" } });

const SECRET_KEY = "NITRO_TIENDITA_2026_JWT_SECRET";
const ADMIN_REGISTRATION_CODE = "Edutv"; 

// --- MIDDLEWARES DE SEGURIDAD (REQUERIMIENTO PROFE) ---
app.use(helmet({ crossOriginResourcePolicy: false }));
app.use(cors());
app.use(express.json());
app.use(morgan('dev')); // Auditoría y Monitoreo en consola
app.use('/uploads', express.static(path.join(__dirname, 'uploads')));

const limiter = rateLimit({ windowMs: 15 * 60 * 1000, max: 100 });
app.use('/api/', limiter);

const db = mysql.createConnection({
  host: 'localhost', user: 'root', password: 'root', database: 'mi-tiendita'
});

// --- AUTORIZACIÓN JWT (RBAC) ---
const verificarToken = (req, res, next) => {
  const token = req.headers['authorization']?.split(' ')[1];
  if (!token) return res.status(403).json({ error: "No autorizado" });
  jwt.verify(token, SECRET_KEY, (err, decoded) => {
    if (err) return res.status(401).json({ error: "Sesión expirada" });
    req.user = decoded;
    next();
  });
};

// --- CONFIGURACIÓN DE FOTOS ---
const storage = multer.diskStorage({
  destination: 'uploads/',
  filename: (req, file, cb) => cb(null, Date.now() + path.extname(file.originalname))
});
const upload = multer({ storage });

// --- SOCKETS (SISTEMA DE EXPULSIÓN - SUPER USUARIO) ---
let conectados = {};
io.on('connection', (socket) => {
  socket.on('register', (username) => {
    conectados[username] = socket.id;
    io.emit('update_online', Object.keys(conectados));
  });
  socket.on('disconnect', () => {
    for (let user in conectados) {
      if (conectados[user] === socket.id) delete conectados[user];
    }
    io.emit('update_online', Object.keys(conectados));
  });
});

// --- RUTAS DE AUTENTICACIÓN ---
app.post('/api/register', async (req, res) => {
  const { usuario, email, telefono, clave, rol, codigoAdmin } = req.body;
  if (rol === 'admin' && codigoAdmin !== ADMIN_REGISTRATION_CODE) {
    return res.status(403).json({ error: "Código de Admin inválido" });
  }
  try {
    const hash = await bcrypt.hash(clave, 10);
    const sql = 'INSERT INTO usuarios (usuario, email, telefono, clave, rol) VALUES (?, ?, ?, ?, ?)';
    db.query(sql, [usuario, email, telefono, hash, rol], (err) => {
      if (err) return res.status(500).json({ error: "El usuario o email ya existe" });
      res.json({ success: true });
    });
  } catch (e) { res.status(500).json({ error: "Error interno" }); }
});

app.post('/api/login', (req, res) => {
  const { usuario, clave } = req.body;
  db.query('SELECT * FROM usuarios WHERE usuario = ?', [usuario], async (err, result) => {
    if (result && result.length > 0) {
      const match = await bcrypt.compare(clave, result[0].clave);
      if (match) {
        const token = jwt.sign({ id: result[0].id, rol: result[0].rol, user: result[0].usuario }, SECRET_KEY, { expiresIn: '4h' });
        res.json({ success: true, token, user: result[0].usuario, rol: result[0].rol, email: result[0].email });
      } else res.status(401).json({ error: "Clave incorrecta" });
    } else res.status(404).json({ error: "Usuario no existe" });
  });
});

// --- RUTAS DE PRODUCTOS (CON PROTECCIÓN RBAC) ---
app.get('/api/productos', verificarToken, (req, res) => {
  db.query('SELECT * FROM productos', (err, result) => res.json(result));
});

app.get('/api/productos/buscar', verificarToken, (req, res) => {
  const q = `%${req.query.q}%`;
  db.query('SELECT * FROM productos WHERE nombre LIKE ?', [q], (err, result) => res.json(result));
});

app.post('/api/productos', verificarToken, upload.single('imagen'), (req, res) => {
  if (req.user.rol !== 'admin') return res.status(403).json({ error: "No eres admin" });
  const { nombre, stock, precio_venta } = req.body;
  const imagen = req.file ? req.file.filename : null;
  const sql = 'INSERT INTO productos (nombre, imagen, stock, precio_venta, categoria) VALUES (?, ?, ?, ?, "General")';
  db.query(sql, [nombre, imagen, stock, precio_venta], (err) => res.json({ success: true }));
});

app.delete('/api/productos/:id', verificarToken, (req, res) => {
  if (req.user.rol !== 'admin') return res.status(403).json({ error: "Permiso denegado" });
  db.query('DELETE FROM productos WHERE id = ?', [req.params.id], (err) => res.json({ success: true }));
});

app.get('/api/stats', verificarToken, (req, res) => {
  db.query('SELECT COUNT(*) AS total, IFNULL(SUM(stock * precio_venta), 0) AS valor, (SELECT COUNT(*) FROM productos WHERE stock < 10) AS bajo FROM productos', (err, result) => {
    res.json({ total_productos: result[0].total, valor_inventario: result[0].valor, bajo_stock: result[0].bajo });
  });
});

// --- SISTEMA DE EXPULSIÓN ---
app.post('/api/kick', verificarToken, (req, res) => {
  if (req.user.rol !== 'superadmin' && req.user.user !== 'eduardo') return res.status(403).json({ error: "No tienes este poder" });
  const { usuarioExpulsar } = req.body;
  const socketId = conectados[usuarioExpulsar];
  if (socketId) {
    io.to(socketId).emit('force_logout');
    res.json({ success: true });
  } else res.status(404).json({ error: "Usuario no conectado" });
});

server.listen(5000, () => console.log('🚀 SERVIDOR NITRO REAL EN PUERTO 5000'));
